import math

class Solution:
    def replaceNonCoprimes(self, nums):
        arr = list(nums)
        changed = True
        while changed:
            changed = False
            i = 0
            merged = []
            while i < len(arr):
                if i + 1 < len(arr) and math.gcd(arr[i], arr[i + 1]) > 1:
                    merged.append(arr[i] * arr[i + 1] // math.gcd(arr[i], arr[i + 1]))
                    i += 2
                    changed = True
                else:
                    merged.append(arr[i])
                    i += 1
            arr = merged
        return arr

