import math

class Solution:
    def replaceNonCoprimes(self, nums):
        stack = []
        for x in nums:
            cur = x
            while stack:
                g = math.gcd(stack[-1], cur)
                if g > 1:
                    cur = stack.pop() * cur // g
                else:
                    break
            stack.append(cur)
        return stack

