var replaceNonCoprimes = function(nums) {
    const stack = [];
    for (const x of nums) {
        let cur = x;
        while (stack.length) {
            const g = gcd(stack[stack.length - 1], cur);
            if (g > 1) {
                cur = stack.pop() * cur / g;
            } else {
                break;
            }
        }
        stack.push(cur);
    }
    return stack;
};
